import React, { Component } from "react";
import { Icon, Avatar } from "antd";

class LandingTwo extends Component {
  render() {
    return (
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          flexDirection: "row",
          height: "45vh",
          paddingBottom: "5vh",
          backgroundColor: "#1890ff"
        }}
      >
        <div
          style={{
            display: "flex",
            flexDirection: "column"
          }}
        >
          <div>
            <div
              style={{
                fontWeight: "bold",
                fontSize: "4vw",
                color: "white",
                textAlign: "center"
              }}
            >
              Ni-hilism.
            </div>
            <div
              style={{
                fontWeight: "bold",
                fontSize: "1vw",
                color: "white",
                textAlign: "center"
              }}
            >
              The philosophy I follow when I'm not tired.
            </div>

            <div>
              <Avatar size="large" icon="user" />
            </div>
          </div>
        </div>
      </div>
    );
  }
}

export default LandingTwo;
